SourceCode.Declaration:
/// <summary>
/// Data contract for the Hugo Boss Retail Statement Payment Summary report.
/// Holds user-facing parameters: Store IDs (multi-select), From Date, and To Date.
/// Statement Type = Financial is hard-coded in the Data Provider, not exposed here.
/// </summary>
[DataContractAttribute]
class HBRetailStatementPaymentContract
{
    List        storeIds;
    TransDate   fromDate;
    TransDate   toDate;

}

Method.Source:
[
    DataMemberAttribute('StoreIds'),
    AifCollectionTypeAttribute('StoreIds', Types::String),
    SysOperationLabelAttribute(literalStr("Store"))
]
public List parmStoreIds(List _storeIds = storeIds)
{
    storeIds = _storeIds;
    return storeIds;
}

[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("From Date"))
]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("To Date"))
]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}
